  ('dietitian-moex-00473', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於糖解作用及糖質新生作用的敘述，下列何者錯誤？', '["糖解作用經由pyruvate kinase將phosphoenolpyruvate轉變為pyruvate", "糖質新生作用經由pyruvate carboxylase及phosphoenolpyruvate carboxykinase將pyruvate轉變為 phosphoenolpyruvate", "糖解作用經由phosphoenolpyruvate轉變為pyruvate時，會生成ATP", "糖質新生作用將pyruvate轉變為phosphoenolpyruvate時，利用ATP作為磷酸根的提供者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00474', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '細胞膜磷脂質（phospholipid）的中間代謝產物可以作為二級傳訊者，何者可促進內質網中鈣離子釋放？', '["雙酸甘油酯（diacylglycerol）", "膽鹼（choline）", "肌醇三磷酸（inositol 1,4,5-triphosphate）", "蛋白質激酶 A（protein kinase A）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00475', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '脂肪組織中hormone-sensitive lipase（HSL）可將三酸甘油酯分解釋出脂肪酸，下列何種荷爾蒙可抑制HSL 活性？', '["Adrenocorticotropic hormone（ACTH）", "Epinephrine", "Glucagon", "Insulin"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00476', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於膽固醇合成過程關鍵酵素HMG CoA reductase活性的調節，下列敘述何者正確？', '["胰島素（insulin）透過將HMG CoA reductase磷酸化使其活化", "昇糖素（glucagon）透過將HMG CoA reductase去磷酸化使其活化", "細胞內膽固醇濃度低時，會經由SREBP（sterol regulatory element-binding proteins）活化HMG CoA reductase的轉錄作用", "細胞內膽固醇濃度高時，會經由LXR（liver X receptor）活化HMG CoA reductase的轉錄作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00477', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列那一個apolipoprotein與血管內皮細胞的脂蛋白脂解酶（lipoprotein lipase）活化有關？', '["apolipoprotein A-1", "apolipoprotein B-48", "apolipoprotein C-2", "apolipoprotein E"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00478', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於穀胱甘肽（glutathione）的敘述，下列何者正確？', '["是屬於三胜肽（tripeptide）的結構", "由glycine、isoleucine及glutamate三種胺基酸組合而成", "其結構含有硫氫鍵（-SH）結構，在細胞內通常以還原態的GSSG形式存在", "蛋白質營養狀況差時，體內合成穀胱甘肽的濃度會增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00479', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '胺基酸依序結合成一條多胜肽鏈的結構為下列何者？', '["初級結構（primary structure）", "次級結構（secondary structure）", "三級結構（tertiary structure）", "四級結構（quaternary structure）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00480', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於DNA（deoxyribonucleic acid）結構的敘述，下列何者正確？', '["DNA之去氧核苷酸（deoxynucleotide）組成，包括去氧腺嘌呤核苷酸（deoxyadenylate）、去氧胞嘧啶核 苷酸（deoxycytidylate）、胸腺嘧啶核苷酸（thymidylate）及尿嘧啶核苷酸（uridylate）", "DNA分子之去氧腺苷核苷酸（deoxyadenosine nucleotide）濃度與胸苷核苷酸（thymidine nucleotide） 濃度相同", "DNA雙股螺旋結構主要是由嘌呤（purine）與嘧啶（pyrimidine）間的共價鍵（covalent bond）來維繫", "大部分DNA雙股螺旋是左旋（left handed），即逆時鐘形式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00481', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於荷爾蒙與其合成所需前驅物質（precursor）之對應，下列何者錯誤？', '["皮質醇（cortisol）與膽固醇（cholesterol）", "雌激素（estrogen）與膽固醇（cholesterol）", "正腎上腺素（norepinephrine）與色胺酸（tryptophan）", "甲狀腺素（thyroxine）與碘（iodine）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00482', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者主要可藉由DNA結合蛋白作用於荷爾蒙反應元件（hormone response element），調控特定基因的 表現？', '["乙醯膽鹼（acetylcholine）", "兒茶酚胺（catecholamines）", "昇糖素（glucagon）", "視網酸（retinoic acid）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
